+    NotExecuted,
+    /// Step was already executed successfully - skip
+    AlreadyCompleted {
+        /// When the step was completed
+        completed_at: i64,
+        /// Result from the previous execution
+        previous_result: Option<String>,
+    },
+    /// Step was started but not completed - may need recovery
+    PartiallyExecuted {
